import{_ as a,a as i}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as l,o as r,c as t,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"WebDAV Site Erişimi (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Safety/webdav-site-access.md","filePath":"tr-TR/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),d={name:"tr-TR/Safety/webdav-site-access.md"};function s(o,e,m,b,k,h){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="webdav-site-erisimi-beta" tabindex="-1">WebDAV Site Erişimi (Beta) <a class="header-anchor" href="#webdav-site-erisimi-beta" aria-label="Permalink to &quot;WebDAV Site Erişimi (Beta)&quot;">​</a></h1><p>Security Settings içindeki WebDAV ayarı, ImgBed sitenizi WebDAV endpoint olarak sunar.</p><p>Etkinleştirildikten sonra Windows, macOS, mobil dosya yöneticileri veya WebDAV uyumlu herhangi bir istemciyle ImgBed dosyalarını uzak klasör gibi gezebilir, yükleyebilir, silebilir ve yönetebilirsiniz.</p><p>Bu, sitenin WebDAV erişim girişidir. Yükleme Ayarları&#39;ndaki WebDAV depolama kanalından farklıdır. Yükleme kanalı dosyaları üçüncü taraf WebDAV hizmetinde saklar. Bu ayar ise ImgBed sitenizin istemcilere WebDAV erişimi sağlamasını sağlar.</p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Yönetim panelini açın, ardından şuraya gidin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Kullanılabilir ayarlar:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="bu-ozellik-ne-ise-yarar" tabindex="-1">Bu Özellik Ne İşe Yarar? <a class="header-anchor" href="#bu-ozellik-ne-ise-yarar" aria-label="Permalink to &quot;Bu Özellik Ne İşe Yarar?&quot;">​</a></h2><p>WebDAV etkinleştirildikten sonra ImgBed sabit bir erişim URL&#39;si sağlar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>ImgBed dosya dizininize bağlanmak için bu URL&#39;yi kullanın.</p><p>İyi kullanım örnekleri:</p><ul><li>ImgBed dosyalarını bilgisayar dosya yöneticinizden doğrudan gezmek.</li><li>Görselleri WebDAV klasörüne sürükleyerek yüklemek.</li><li>ImgBed klasörlerini yerel dosya yöneticisinden düzenlemek.</li><li>WebDAV uyumlu yazılımlarla görselleri senkronize etmek veya yönetmek.</li><li>Yönetim panelini açmadan ImgBed içeriğine erişmek.</li></ul><h2 id="ayarlar" tabindex="-1">Ayarlar <a class="header-anchor" href="#ayarlar" aria-label="Permalink to &quot;Ayarlar&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint&#39;i açar.</p><p>Kapalıyken istemciler WebDAV üzerinden bağlanamaz.</p><h3 id="username-ve-password" tabindex="-1">Username ve Password <a class="header-anchor" href="#username-ve-password" aria-label="Permalink to &quot;Username ve Password&quot;">​</a></h3><p>Bu kimlik bilgileri WebDAV istemcileri bağlanırken kullanılır.</p><p>Ayrı bir WebDAV kullanıcı adı ve parolası kullanın. Yönetici parolasını veya yükleme parolasını yeniden kullanmayın.</p><p>Username veya password boşsa WebDAV istemcileri düzgün bağlanamaz.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode, WebDAV istemcilerinin görsel okurken hangi görsel URL&#39;sini tercih edeceğini belirler.</p><p>Yaygın seçenekler:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Açıklama</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed bağlama göre seçim yapar. Normal kullanım için önerilir.</td></tr><tr><td>Original</td><td>Özgün görselleri tercih eder.</td></tr><tr><td>Thumbnail</td><td>Küçük görselleri tercih eder. Hızlı önizleme için kullanışlıdır.</td></tr></tbody></table><p>Emin değilseniz <code>Smart loading</code> bırakın.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel WebDAV yüklemeleri için kullanılır.</p><p>Windows veya başka bir istemciden WebDAV dizinine dosya kopyaladığınızda ImgBed bunları seçili default upload channel üzerinden yükler.</p><p>Default channel seçilmemişse gezinme çalışabilir, ancak yükleme başarısız olabilir.</p><h2 id="windows-11-de-webdav-a-erisim" tabindex="-1">Windows 11&#39;de WebDAV&#39;a Erişim <a class="header-anchor" href="#windows-11-de-webdav-a-erisim" aria-label="Permalink to &quot;Windows 11&#39;de WebDAV&#39;a Erişim&quot;">​</a></h2><p>Windows 11 WebDAV&#39;ı network location olarak ekleyebilir.</p><ol><li><code>This PC</code> açın.</li><li><code>Add a network location</code> seçin.</li><li><code>https://your-domain.com/dav</code> girin.</li><li>İstendiğinde WebDAV username ve password girin.</li><li>Sihirbazı tamamlayın. Ardından WebDAV dizini File Explorer içinde açılabilir.</li></ol><p><img src="'+a+'" alt="Windows 11&#39;de WebDAV ekleme" loading="lazy"></p><p>Eklendikten sonra WebDAV dizini Windows File Explorer içinde görünür. Normal klasör gibi açabilir, kopyalayabilir ve yönetebilirsiniz.</p><p><img src="'+i+'" alt="Windows&#39;ta WebDAV" loading="lazy"></p><h2 id="desteklenen-islemler" tabindex="-1">Desteklenen İşlemler <a class="header-anchor" href="#desteklenen-islemler" aria-label="Permalink to &quot;Desteklenen İşlemler&quot;">​</a></h2><p>Başarılı WebDAV bağlantısından sonra genellikle şunları yapabilirsiniz:</p><ul><li>Dosya ve klasörleri görüntüleme.</li><li>Dosya yükleme.</li><li>Klasör oluşturma.</li><li>Dosya veya klasör yeniden adlandırma.</li><li>Dosya taşıma.</li><li>Dosya silme.</li></ul><p>WebDAV günlük erişim ve küçük ölçekli dosya yönetimi için daha uygundur. Büyük taşıma işlemleri, toplu silme veya karmaşık düzenlemeler için yönetim panelini kullanın.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Başarılı WebDAV bağlantıları Login Device Management içindeki WebDAV sekmesinde de görünür.</p><p>WebDAV istemcilerini buradan inceleyebilir ve gerektiğinde eski cihazları zorla çevrimdışı bırakabilirsiniz.</p><p>WebDAV username veya password değiştirirseniz eski istemcilerin yeniden giriş yapması gerekir.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-surekli-username-ve-password-soruyor" tabindex="-1">Windows Sürekli Username ve Password Soruyor <a class="header-anchor" href="#windows-surekli-username-ve-password-soruyor" aria-label="Permalink to &quot;Windows Sürekli Username ve Password Soruyor&quot;">​</a></h3><p>Şunları kontrol edin:</p><ul><li>URL <code>https://your-domain.com/dav</code> olmalıdır.</li><li>Username ve password WebDAV ayarlarıyla eşleşmelidir.</li><li>WebDAV etkin olmalıdır.</li><li>Site HTTPS üzerinden erişilebilir olmalıdır.</li></ul><h3 id="gezme-calısıyor-ama-yukleme-basarısız" tabindex="-1">Gezme Çalışıyor ama Yükleme Başarısız <a class="header-anchor" href="#gezme-calısıyor-ama-yukleme-basarısız" aria-label="Permalink to &quot;Gezme Çalışıyor ama Yükleme Başarısız&quot;">​</a></h3><p><code>Default channel</code> ayarını kontrol edin.</p><p>WebDAV yüklemeleri için default upload channel gerekir. Eksik, devre dışı veya hatalı yapılandırılmışsa yüklemeler başarısız olabilir.</p><h3 id="erisim-hızı-kararsız" tabindex="-1">Erişim Hızı Kararsız <a class="header-anchor" href="#erisim-hızı-kararsız" aria-label="Permalink to &quot;Erişim Hızı Kararsız&quot;">​</a></h3><p>WebDAV performansı istemciye, ağa, dosya sayısına ve default upload channel&#39;a bağlıdır.</p><p>Bir dizinde çok sayıda dosya varsa hepsini tek dizinde tutmak yerine klasörlere ayırın.</p><h2 id="guvenlik-onerileri" tabindex="-1">Güvenlik Önerileri <a class="header-anchor" href="#guvenlik-onerileri" aria-label="Permalink to &quot;Güvenlik Önerileri&quot;">​</a></h2><ul><li>WebDAV erişimi için HTTPS kullanın.</li><li>Güçlü parola belirleyin.</li><li>WebDAV parolasını güvenmediğiniz kişilerle paylaşmayın.</li><li>Kullanmadığınızda WebDAV&#39;ı kapatın.</li><li>Login Device Management içinde kullanılmayan WebDAV cihazlarını düzenli olarak temizleyin.</li></ul><h2 id="webdav-yukleme-dosya-boyutu" tabindex="-1">WebDAV Yükleme Dosya Boyutu <a class="header-anchor" href="#webdav-yukleme-dosya-boyutu" aria-label="Permalink to &quot;WebDAV Yükleme Dosya Boyutu&quot;">​</a></h2><p>WebDAV istemcileri tarayıcı yükleme sayfasındaki büyük dosya parçalama akışını kullanmaz. Aşağıdaki önerilen limitlerin üzerindeki dosyalar için web yükleme sayfasını kullanın.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">WebDAV için Önerilen Tek Dosya Limiti</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const c=l(d,[["render",s]]);export{u as __pageData,c as default};
